entry.content:
  下面的代码继承了 std::streambuf 改变了 ostream 的行为，并自定义了打印操作将结果送到 stdout，而不是 std::cout 中。
其中的 print 函数是仿 C++23 std::print 的，功能仅仅是打印参数，在笔记 实现简单的花括号插值打印 中实现。
struct membuf : std::streambuf { membuf(char *p, size_t n) { setg(p, p, p + n); // set read pointers setp(p, p + n); } void flush() { auto p = pbase(), e = pptr(); fwrite(p, 1, e - p, stdout); setp(p, e); // reset write pointers } private: int overflow(int c) override { flush(); if (c != &#39;\0&#39;) fputc(c, stdout); return c; } }; // A little slower since we have to maintain a different buffer. template &lt;class... Ts&gt; void print_stdout(const char *s, Ts... args) { char buf[512]; membuf mbuf(buf, sizeof(buf)); std::ostream os(&amp;mbuf); print(os, s, args...); mbuf.flush(); }

 这个变量表示 bash 真正的入口程序。这个变量的必要性体现在 source 某个 bash 脚本的时候 $0 不能准确反映入口程序。
#!/bin/bash echo &#34;[$0] vs. [${BASH_SOURCE[0]}]&#34; $ bash ./foo [./foo] vs. [./foo] $ ./foo [./foo] vs. [./foo] $ . ./foo [bash] vs. [./foo] 参考 https://stackoverflow.com/a/35006505/
本来 BASH_SOURCE 是一个数组类型的变量。但是 bash 中使用 $ARR 相当于 ${ARR[0]}，所以也可以简写。

Namespaces - cppreference.com
inline namespace 既本身存在，又将所有内容引入外围（enclosing）名字空间中。相当于名字空间后面加了一句：using namespace X;
例子：
inline namespace A { using Int = int; } int main() { A::Int a; Int b; // 也能成功 }

  例子：
#include &lt;iostream&gt; #include &lt;numeric&gt; #include &lt;vector&gt; int main() { std::vector v{1, 3, 5}; // 模板类参数推导：T=int std::cout &lt;&lt; std::accumulate(begin(v), end(v), 0); // ^^ ^^ ^^ 都是ADL } 使用 begin、end、swap 等函数模板时，先引入其名字到当前空间中，然后再调用，有助于 ADL 查找到性能更优的函数实现：
{ using std::swap; swap(A, B); // 假设 A 和 B 是已经定义的同类型变量 }

  我的理解是：C++ 的协程是无栈的，这意味着协程只是计算任务，仅在运行时需要栈，在 suspend 之后就会保存状态并脱离栈。要想要跨线程转移计算任务（比如实现工作窃取池），只需要将离栈协程在另外一个线程上 resume 即可。
#include &lt;coroutine&gt; #include &lt;iostream&gt; #include &lt;stdexcept&gt; #include &lt;thread&gt; auto switch_to_new_thread(std::jthread&amp; out) { struct awaitable { std::jthread* p_out; bool await_ready() { return false; } void await_suspend(std::coroutine_handle&lt;&gt; h) { std::jthread&amp; out = *p_out; if (out.joinable()) throw std::runtime_error(&#34;Output jthread parameter not empty&#34;); out = std::jthread([h] { h.resume(); }); // Potential undefined behavior: accessing potentially destroyed *this // std::cout &lt;&lt; &#34;New thread ID: &#34; &lt;&lt; p_out-&gt;get_id() &lt;&lt; &#39;
&#39;; std::cout &lt;&lt; &#34;New thread ID: &#34; &lt;&lt; out.get_id() &lt;&lt; &#39;
&#39;; // this is OK } void await_resume() {} }; return awaitable{&amp;out}; } struct task { struct promise_type { task get_return_object() { return {}; } std::suspend_never initial_suspend() { return {}; } std::suspend_never final_suspend() noexcept { return {}; } void return_void() {} void unhandled_exception() {} }; }; task resuming_on_new_thread(std::jthread&amp; out) { std::cout &lt;&lt; &#34;Coroutine started on thread: &#34; &lt;&lt; std::this_thread::get_id() &lt;&lt; &#39;
&#39;; co_await switch_to_new_thread(out); // awaiter destroyed here std::cout &lt;&lt; &#34;Coroutine resumed on thread: &#34; &lt;&lt; std::this_thread::get_id() &lt;&lt; &#39;
&#39;; } int main() { std::jthread out; resuming_on_new_thread(out); } 可能结果：
Coroutine started on thread: 139972277602112 New thread ID: 139972267284224 Coroutine resumed on thread: 139972267284224

包含模型 - The Inclusion Model 通常模板需要被包含在头文件中工作。 注意：函数模板完全特化之后也需要 inline 才能够在头文件中使用，否则会出现不同的翻译单元有重复定义的情况。 改进一：precompiled headers 可以把 pch 理解为编译器中间工作状态的一个 dump。编译器可以在读取到某些源代码之后保存其状态，包括符号表等。如果两个文件中有公共的前缀代码（比如一个标准库的头文件就包含了数千行公共代码），编译器就可以读取预先保存的状态，从而跳过对于这些代码的处理。 很遗憾的是前缀的判定是必须完全相同，即便改变头文件的包含顺序，其中与宏相关的定义也可能结果不同。由于宏无法从模块中导出，模块将可能解决这一痛点。 改进二：explicit template instantiation 只在头文件中留模板函数的声明，而不是定义。然后在其他的源文件中提供特化的定义。 // base.hpp template &lt;class T&gt; T foo(T t); // second.cpp #include &#34;./base.hpp&#34; template &lt;&gt; int foo&lt;int&gt;(int t) { return t; } // main.cpp #include &#34;./base.hpp&#34; int main() { auto x = foo(1); std::cout &lt;&lt; x &lt;&lt; &#39;
&#39;; } 这样不用所有用到函数模板的翻译单元都去编译一遍函数。缺点是只能依赖枚举提供特化。 注意：在 second.cpp 中只提供通用模板函数定义是无法链接的，因为模板函数只是生成规则，并不是具体的函数，会无法匹配。同时，只在 base.hpp 声明特化的函数而不给出定义，试图依赖 second.cpp 的规则去生成函数也是无法链接的。 // base.hpp template &lt;class T&gt; T foo(T t) { return t;} template &lt;&gt; int foo&lt;int&gt;(int t); // second.cpp #include &lt;iostream&gt; #include &#34;./base.hpp&#34; template &lt;&gt; int foo&lt;int&gt;(int t) { std::cout &lt;&lt; &#34;int foo&lt;int&gt;(int t) is called!
&#34;; return t; } // main.cpp #include &#34;./base.hpp&#34; int main() { auto x = foo(1); std::cout &lt;&lt; x &lt;&lt; &#39;
&#39;; } 打印结果： int foo&lt;int&gt;(int t) is called! 1 这说明如果存在函数特化的声明，则不会使用模板函数的规则去在自己的翻译单元生成这个特化的函数。同样，如果注释掉了 second.cpp 中特化函数的定义，将会链接失败。使用这种方式，既可以避免枚举覆盖面的不完善，又能够为通用的一些函数节约编译时间。 改进三：modules 略。

  对于变量而言，其括号表达式的值类别是左值引用。但由于 decltype 有特殊效果，直接对变量 x 使用 decltype(x) 并不遵循这一点，为此可以按照下面说的使用 decltype((x))。
With the keyword decltype (introduced in C++11), it is possible to check the value category of any C++ expression. For any expression x, decltype((x)) (note the double parentheses) yields:
type if x is a prvalue type&amp; if x is an lvalue type&amp;&amp; if x is an xvalue The double parentheses in decltype((x)) are needed to avoid producing the declared type of a named entity in case where the expression x does indeed name an entity (in other cases, the paren-theses have no effect). For example, if the expression x simply names a variable v, the construct without parentheses becomes decltype(v), which produces the type of the variable v rather than a type reﬂecting the value category of the expression x referring to that variable.
例子：
#include &lt;iostream&gt; template&lt;typename T&gt; struct value_category { static constexpr auto value = &#34;prvalue&#34;; }; template&lt;typename T&gt; struct value_category&lt;T&amp;&gt; { static constexpr auto value = &#34;lvalue&#34;; }; template&lt;typename T&gt; struct value_category&lt;T&amp;&amp;&gt; { static constexpr auto value = &#34;xvalue&#34;; }; // Get value category of an expression #define VALUE_CATEGORY(expr) value_category&lt;decltype((expr))&gt;::value #define PRINT(expr) printf(&#34;(%s) : %s\n&#34;, #expr, VALUE_CATEGORY(expr)) int main() { PRINT(4); // prvalue int x; int &amp;y = x; int &amp;&amp;z = (int &amp;&amp;)x; PRINT(x); // lvalue PRINT(y); // lvalue PRINT(z); // lvalue PRINT(x+1); // prvalue }

  C 风格枚举和 C++ 新增的 enum class：
enum { ITEM_A1, ITEM_A2 }; enum B { ITEM_B1, ITEM_B2 }; // 从 C 沿用来的语法： // 1. 底层类型默认为int，但也能手动指定 // 2. 枚举名裸露在外 // 区别： // C 允许前向声明 enum // C++ 允许枚举列表为空；允许在表示类型时省略 enum 关键字；虽然枚举名裸露但也能通过限定名访问 // C++ 新增 enum class enum C { ITEM_C1, ITEM_C2 }; // 类型不再裸露，需要使用限定名访问 // 没有默认底层类型，但是可以手动指定 C++ enum class 禁止了隐式转换，但是用来表示 id 还是不太方便：
#include &lt;type_traits&gt; enum A: int { ITEM_1 }; enum { ITEM_2 }; enum class B: int { ITEM_3 }; // 即便底层类型相同，实际类型也不同 static_assert(! std::is_same_v&lt;int, A&gt;); static_assert(sizeof(int) == sizeof(A)); static_assert(sizeof(int) == sizeof(ITEM_2)); // 枚举不是聚合类 static_assert(! std::is_aggregate_v&lt;A&gt;); static_assert(! std::is_aggregate_v&lt;B&gt;); int main() { [](int){}(ITEM_1); [](int){}(ITEM_2); int b3 = (int)B::ITEM_3; // [](int){}(B::ITEM_3); // no conversion from B to int // [](B){}(b3); // no conversion from int to B [](B){}(B {b3}); // [](B){}( {b3} ); // 即便是花括号也不能推导，因为枚举不是类 // 强类型整数还是用 aggregate 做比较好： // 虽然整数到枚举可以使用构造的方式描述，但枚举到整数只能强制转换 // 作为对比，aggregate 直接访问成员即可 }

  下面的代码中，Bar 能够隐式转换成 Foo。想要重载 Foo 的等于运算符至少有三种方案：
重载全局的 == 运算符 重载 Foo 中的 hidden friend，即 friend bool operator==(Foo const &amp;a, Foo const &amp;b) 重载 bool operator==(Foo const &amp;a) const 第一种方案会污染全局的名字空间，使得 Bar 和 Bar 之间也能通过转换两个参数进行比较；第三种方案允许第二个参数的隐式类型转换，但要求第一个参数必须是 Foo 类型；第二种方案只要求任一个参数为 Foo 类型，使得 ADL 能够参与找到这个函数，另一个参数则可以通过隐式类型转换来得到。
成员函数的劣势是由于查找方式和 this 指针的存在，函数失去了对称性。全局函数的劣势则是没有用上 ADL 的优势，hidden friends 在这种情况比较好。
https://godbolt.org/z/6sxdno3Yh
#include &lt;iostream&gt; #define HIDDEN_FEIDEND 1 struct Foo { int value{}; #ifdef HIDDEN_FEIDEND friend bool operator==(Foo const &amp;a, Foo const &amp;b) { return a.value == b.value; } #endif }; struct Bar { int value{}; // Bar can be converted implicitly to Foo. // `explicit` keyword makes the conversion explicit. // explicit operator Foo() const { return Foo{value}; } }; #ifndef HIDDEN_FEIDEND // Normal operator overload that can be found in global scope bool operator==(Foo const &amp;a, Foo const &amp;b) { return a.value == b.value; } #endif int main() { Bar a{-4}, b{1}; Foo c{2}; // std::cout &lt;&lt; std::boolalpha &lt;&lt; (a == b) &lt;&lt; &#34;\\n&#34;; // ok if no HIDDEN_FEIDEND std::cout &lt;&lt; std::boolalpha &lt;&lt; (a == c) &lt;&lt; &#34;\\n&#34;; // ok std::cout &lt;&lt; std::boolalpha &lt;&lt; (c == a) &lt;&lt; &#34;\\n&#34;; // ok }

  尽管现在的编译器能够正确理解数据成员（含有隐式的 this 指针）的使用，并在看到整个类定义之后再查找名字，类型名的查找则发生的很早，导致使用时可能看不到、或者使用了错误的类型声明。
所以，应该尽可能在类定义的开头写好类型别名。
#include &lt;iostream&gt; #include &lt;type_traits&gt; typedef int length; class Point3d { public: **void mumble(length val) { _val = val; } length mumble() { return _val; } static_assert(std::is_same_v&lt;length, int&gt;); private: typedef float length; length _val; }; int main() {}
